var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PIRATE_FOX_MONITOR_NULL","text":{"KOREA":"오늘 수확이 괜찮은데? 쓸만해 보이는 것들을 많이 건졌어.","JPN":"今日はなかなかの収穫だな。使えそうなものがたくさん手に入ったぞ。","ENG":"Not bad today, not bad. We found a lot of useful-looking things.","TWN":"今天收穫不錯喔？找到了很多看起來有用的東西。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FOX_MONITOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FOX_DIVER_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"PIRATE_FOX_DIVER_NULL","text":{"KOREA":"게다가 주제도 모르고 우리 구역에서 채굴질을 하던 함선도 하나 건지고 말이야.","JPN":"それに、恐れげもなくうちの縄張りで採掘をしていた艦船も獲得したしな。","ENG":"Plus the mining ship that trespassed in our territory.","TWN":"並且還找到了一個竟敢在我們區域開採的艦船。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FOX_MONITOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FOX_DIVER_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PIRATE_FOX_DIVER_NULL","text":{"KOREA":"부지런히 조금만 더 살펴보고 돌아가자고.","JPN":"もう少しだけ確認してから帰ろうや。","ENG":"Let's take a look around for a little longer before we head back.","TWN":"再找找看，然後回去吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FOX_MONITOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FOX_DIVER_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PIRATE_FOX_MONITOR_NULL","text":{"KOREA":"300km 밖에서 급성 차원 폭풍 감지.","JPN":"300km先で突発的な次元暴風を検知した。","ENG":"A sudden dimensional storm detected 300 kilometers away.","TWN":"感知到300km外的急性次元風暴。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FOX_MONITOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FOX_DIVER_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"PIRATE_FOX_MONITOR_NULL","text":{"KOREA":"회항해야 하니까 슬슬 서두르는 게 좋아.","JPN":"そろそろ戻らねば。急いでくれ。","ENG":"We'd better hurry and get out of here.","TWN":"該返航了，動作快點。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FOX_MONITOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FOX_DIVER_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PIRATE_FOX_DIVER_NULL","text":{"KOREA":"잠깐만.","JPN":"ちょっと待て。","ENG":"Wait.","TWN":"等一下。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_DIVER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PIRATE_FOX_DIVER_NULL","text":{"KOREA":"뭔가 발견한 거 같다. 화면 공유할게.","JPN":"何か見つけたみたいだぞ。画面共有する。","ENG":"I found something. Let me share this screen.","TWN":"發現一個東西了，我給你共享畫面。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_DIVER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PIRATE_FOX_MONITOR_NULL","text":{"KOREA":"뭐야 이건? 말로만 듣던 구 관리국의 유물 같은 건가?","JPN":"なんだ、これは？　噂に聞いていた旧管理局の遺物か？","ENG":"What's this? Some of that Old Administration legacy tech that I've only heard about?","TWN":"這是什麼？難道是傳聞中的舊管理局遺物？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PIRATE_FOX_MONITOR_NULL","text":{"KOREA":"이런 엄청난 물건이 왜 시가지 쪽에 있는 거지?","JPN":"なんでこんなモノが市街地にあるんだ？","ENG":"If it is, what's it doing out there on the street?","TWN":"這種東西為什麼會在市區？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PIRATE_FOX_DIVER_NULL","text":{"KOREA":"......잘은 모르겠지만, 오늘 운수가 좋군. 일단 가지고 돌아가겠다.","JPN":"……ワケはわからんが今日はツイてるな。\\nとりあえず持って帰ろうぜ。","ENG":"Beats me, but today must be our lucky day. I'll bring it with me.","TWN":"……不知道，今天運氣太好了，先帶回去再說。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PIRATE_FOX_DIVER_NULL","text":{"KOREA":"부상 성공. 휘말리기 전에 아슬아슬하게 벗어났군.","JPN":"浮上に成功。巻き込まれるギリギリセーフだったな。","ENG":"Surfacing succeeded. If we waited one more minute, we could have gotten swept into that storm.","TWN":"躍出成功，差點就被捲進去了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_DIVER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_27"},{"id":"L24_1","type":"dialog","speaker":"PIRATE_FOX_DIVER_NULL","text":{"KOREA":"이거 어떻게 켜는 건지 알 것 같아? 딱히 전원버튼 같은 건 안 보이는데.","JPN":"これ、どうやってつけるのかわかるか？　電源ボタンが\\n見当たらないが。","ENG":"Do you know how to turn this thing on? I don't see a power button on it.","TWN":"你知道這個怎麼打開嗎？好像沒有電源按鈕。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FOX_DIVER_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PIRATE_FOX_MONITOR_NULL","text":{"KOREA":"내버려둬. 전문가에게 맡겨서 뜯어보면 얼마짜리인지 알 수 있겠지.","JPN":"放っておけ。専門家に預けてみりゃあ価値がわかるだろうよ。","ENG":"Leave it alone. We should find an expert to open it and find out how much it's worth.","TWN":"別弄了，給專家看看就能知道它值多少錢了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FOX_DIVER_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"PIRATE_FOX_MONITOR_NULL","text":{"KOREA":"구 관리국 유물은 매물이 거의 없다시피 하니까, 업계에선 부르는 게 값일 거야.","JPN":"旧管理局の遺物はレアだから言い値で売れるだろうな。","ENG":"Since Old Administration tech is almost nonexistent in the market, we should be able to set our own price for it.","TWN":"舊管理局遺物有價無市，一定能賣出天價。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FOX_DIVER_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"PIRATE_FOX_DIVER_NULL","text":{"KOREA":"으하하, 이거 완전 횡재잖아?","JPN":"うへへ、こりゃあめっけ物じゃないか。","ENG":"Heh heh heh. We've got us a windfall!","TWN":"哈哈哈，發財啦！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FOX_DIVER_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"그리고, 그런 엄청난 물건의 무허가 도굴을 관리국에 걸렸다간 부르는 게 형량일 테고 말이지.","JPN":"まあ、そんなすごいモノの無許可盗掘を管理局に\\n知られたら、量刑もはね上がるだろうがな。","ENG":"And you should get your own prison sentences, for acquiring such a valuable object without the Administration's permission.","TWN":"不僅如此，如果被管理局發現未經許可挖掘，刑量也一定不會低。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FOX_DIVER_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L31_1","type":"dialog","speaker":"PIRATE_FOX_DIVER_NULL","text":{"KOREA":"음? 방금 누가 굉장히 재수없는 소릴 한 거 같은데?","JPN":"ああ？　いま誰か縁起でもねえことをほざいたか？","ENG":"Mm? Who's this smarty-pants?","TWN":"嗯？我好像聽到有人在說混帳話？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FOX_DIVER_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"PIRATE_FOX_DIVER_NULL","text":{"KOREA":"어떤 눈치 없는 신참이야?! 교육 똑바로 안 시켜?","JPN":"空気を読まねえ青二才はどこのどいつだ！？\\n口を慎めや！","ENG":"Was that a recruit? Who trained him?","TWN":"這是哪個不識趣的新人？！給我好好教育他！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_DIVER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_05"},{"id":"L35_1","type":"dialog","speaker":"LEE_FRONTIER_NULL_NULL","text":{"KOREA":"신참은 아니고......","JPN":"青二才ではなく……","ENG":"Not a recruit.","TWN":"不是新人……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEE_FRONTIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L36_1","type":"dialog","speaker":"LEE_FRONTIER_NULL_NULL","text":{"KOREA":"너희 같은 놈들 때려잡는 일을 주업으로 하는 경력직 베테랑이지.","JPN":"お前らのような連中を捕まえる専門家で、バリバリのベテランだぜ。","ENG":"But a veteran, who catches pirates like you for a living.","TWN":"是專門抓你們這些混蛋的資深老手。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEE_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PIRATE_FOX_MONITOR_NULL","text":{"KOREA":"너, 너는 뭐냐?","JPN":"な、なんだ、お前？","ENG":"W-who are you?","TWN":"你、你是誰？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_MONITOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PIRATE_FOX_MONITOR_NULL","text":{"KOREA":"어떻게 함선으로 들어온 거야?","JPN":"どうやって艦船の中に入った？","ENG":"How did you sneak in?","TWN":"你是怎麼進入艦船的？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_MONITOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEE_FRONTIER_NULL_NULL","text":{"KOREA":"그냥 정문으로 들어왔는데?","JPN":"普通に正面から入ってきたが？","ENG":"I didn't sneak in; I came through the main door.","TWN":"就是從正門進的呀？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEE_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEE_FRONTIER_NULL_NULL","text":{"KOREA":"물론 어떻게 열었냐고 묻느냐면......","JPN":"どうやって開けたかというと……","ENG":"Of course, if you're asking how I opened it...","TWN":"你如果想問怎樣開的門……"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEE_FRONTIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MAYA_FRONTIER_NULL_NULL","text":{"KOREA":"콰쾅! 하고 터트리니까 활짝 열렸어요~!","JPN":"ドドン！って爆発させたら、パアッと開いたのです～！","ENG":"Kaboom! We blew it off its hinges!","TWN":"當然是哐哐！一炸，門就炸開了呀～！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L42_1","type":"dialog","speaker":"PIRATE_FOX_MONITOR_NULL","text":{"KOREA":"로, 로켓탄?","JPN":"ロ、ロケット弾？","ENG":"R-rocket launcher?","TWN":"火，火箭彈？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_MONITOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PIRATE_FOX_MONITOR_NULL","text":{"KOREA":"저딴 재래식 무기에 차원함선의 해치가 뚫렸다고?","JPN":"あんな古臭い武器に次元艦船のハッチがやられたと？","ENG":"That antiquated weapon blew our dimensional ship's hatch off its hinges?","TWN":"次元船艦的艙口竟被那種舊式武器炸開了？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_MONITOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NINA_FRONTIER_NULL_NULL","text":{"KOREA":"자, 얌전히 투항해.","JPN":"さあ、おとなしく投降しろ。","ENG":"Now, surrender when we ask nicely.","TWN":"來，乖乖投降吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NINA_FRONTIER_NULL_NULL","text":{"KOREA":"안 그러면......","JPN":"さもなければ……","ENG":"Or...","TWN":"不然……"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PIRATE_FOX_DIVER_NULL","text":{"KOREA":"해, 해적사냥꾼이다!","JPN":"か、海賊狩りだ！","ENG":"P-pirate hunters!","TWN":"是海，海盜獵人！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_DIVER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PIRATE_FOX_DIVER_NULL","text":{"KOREA":"전부 없애버려!","JPN":"皆殺しにしてしまえ！","ENG":"Get rid of them all!","TWN":"全都殺掉！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_DIVER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L48_1","type":"dialog","speaker":"LEE_FRONTIER_NULL_NULL","text":{"KOREA":"옳지, 마음에 들어. 그렇게 나오셔야지.","JPN":"だよな、気に入ったぜ。そう来なくちゃな。","ENG":"Yes, that's right. Bring it on.","TWN":"好，我喜歡，就該如此。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEE_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"NINA_FRONTIER_NULL_NULL","text":{"KOREA":"......하아, 늘 이런 식이라니까.","JPN":"……はあ、いつもの展開か。","ENG":"*Sigh* Here we go again.","TWN":"……唉，每次都是這樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};